import React from 'react';

const PeerList = ({ 
  peers, 
  availablePeers, 
  myId, 
  onConnect, 
  selectedPeer,
  setSelectedPeer
}) => {
  return (
    <div className="peer-list">
      <h3>Devices</h3>
      
      <div className="peer-section">
        <h4>Connected ({peers.length})</h4>
        <ul>
          <li key="broadcast">
            <label>
              <input
                type="radio"
                name="peer"
                checked={selectedPeer === 'all'}
                onChange={() => setSelectedPeer('all')}
              />
              Broadcast to all
            </label>
          </li>
          
          {peers.map(peerId => (
            <li key={peerId}>
              <label>
                <input
                  type="radio"
                  name="peer"
                  checked={selectedPeer === peerId}
                  onChange={() => setSelectedPeer(peerId)}
                />
                {peerId}
              </label>
            </li>
          ))}
        </ul>
      </div>

      <div className="peer-section">
        <h4>Available</h4>
        {availablePeers.length > 0 ? (
          <ul>
            {availablePeers.map(peerId => (
              <li key={peerId}>
                {peerId}
                <button onClick={() => onConnect(peerId)}>Connect</button>
              </li>
            ))}
          </ul>
        ) : (
          <p>No available peers found</p>
        )}
      </div>

      <div className="my-id">
        <strong>Your ID:</strong> {myId}
      </div>
    </div>
  );
};

export default PeerList;