import React, { useState, useEffect, useRef } from 'react';
import { initP2P, sendMessage, connectToPeer } from './lib/p2p';
import { encryptMessage, decryptMessage } from './lib/crypto';
import MessageList from './components/MessageList';
import MessageInput from './components/MessageInput';
import PeerList from './components/PeerList';
import ConnectionStatus from './components/ConnectionStatus.jsx';

function App() {
  const [messages, setMessages] = useState([]);
  const [peers, setPeers] = useState([]);
  const [myId, setMyId] = useState('');
  const [availablePeers, setAvailablePeers] = useState([]);
  const inputRef = useRef();
  const [selectedPeer, setSelectedPeer] = useState('all');

  useEffect(() => {
    const initialize = async () => {
      const { peerId } = await initP2P({
        onMessage: (encryptedMsg) => {
          const msg = decryptMessage(encryptedMsg);
          if (msg.destination === peerId || msg.destination === 'all') {
            setMessages(prev => [...prev, msg]);
          }
        },
        onPeerConnected: (newPeers) => setPeers(newPeers)
      });
      setMyId(peerId);
    };

    initialize();

    return () => {
      // Cleanup
    };
  }, []);

  const handleSend = (text, destination) => {
    const msg = {
      id: crypto.randomUUID(),
      text,
      sender: myId,
      destination,
      timestamp: Date.now(),
      hops: 0,
      ttl: 10
    };
    
    const encrypted = encryptMessage(msg);
    sendMessage(encrypted, destination);
    setMessages(prev => [...prev, msg]);
  };

  const handleConnect = (peerId) => {
    connectToPeer(peerId, 
      (encryptedMsg) => {
        const msg = decryptMessage(encryptedMsg);
        setMessages(prev => [...prev, msg]);
      },
      setPeers
    );
  };

  const discoverPeers = async () => {
    // В реальном приложении здесь будет запрос к локальному серверу
    // или использование mDNS/WebRTC для обнаружения
    console.log("Discovery not implemented yet");
  };

  return (
    <div className="app">
      <h1>Offline Messenger</h1>
      <ConnectionStatus peerId={myId} peerCount={peers.length} />
      
      <div className="discovery-section">
        <button onClick={discoverPeers}>Discover Peers</button>
      </div>

      <div className="main-content">
        <PeerList 
          peers={peers} 
          availablePeers={availablePeers}
          myId={myId} 
          onConnect={handleConnect}
          selectedPeer={selectedPeer}
          setSelectedPeer={setSelectedPeer}
        />
        
        <div className="chat-area">
          <MessageList messages={messages} myId={myId} />
          <MessageInput 
            onSend={handleSend} 
            inputRef={inputRef}
            selectedPeer={selectedPeer}
          />
        </div>
      </div>
    </div>
  );
}

export default App;