import Peer from 'peerjs';

let peerInstance;
const connections = {};
const pendingMessages = {};

const handleReceivedMessage = (message, conn, onMessage) => {
  onMessage(message);
  
  // Отправляем подтверждение
  if (message.destination === peerInstance.id) {
    conn.send({
      type: 'ack',
      messageId: message.id
    });
  }
};

const setupConnection = (conn, onMessage, onPeerConnected) => {
  conn.on('open', () => {
    console.log(`Connected to ${conn.peer}`);
    connections[conn.peer] = conn;
    onPeerConnected(Object.keys(connections));
    
    conn.on('data', (data) => {
      if (data.type === 'message') {
        handleReceivedMessage(data.payload, conn, onMessage);
      } else if (data.type === 'ack') {
        console.log(`Message ${data.messageId} delivered`);
      }
    });
    
    // Отправляем ожидающие сообщения
    if (pendingMessages[conn.peer]) {
      pendingMessages[conn.peer].forEach(msg => conn.send(msg));
      delete pendingMessages[conn.peer];
    }
  });
};

export const initP2P = ({ onMessage, onPeerConnected }) => {
  return new Promise((resolve) => {
    peerInstance = new Peer();
    
    peerInstance.on('open', (id) => {
      console.log(`Peer initialized with ID: ${id}`);
      
      peerInstance.on('connection', (conn) => {
        setupConnection(conn, onMessage, onPeerConnected);
      });
      
      resolve({ peerId: id });
    });
    
    peerInstance.on('error', (err) => {
      console.error('PeerJS error:', err);
    });
  });
};

export const sendMessage = (message, destination) => {
  const packet = { type: 'message', payload: message };
  
  if (destination === 'all') {
    Object.values(connections).forEach(conn => {
      conn.send(packet);
    });
  } else {
    if (connections[destination]) {
      connections[destination].send(packet);
    } else {
      if (!pendingMessages[destination]) {
        pendingMessages[destination] = [];
      }
      pendingMessages[destination].push(packet);
      console.log(`Message queued for ${destination}`);
    }
  }
};

export const connectToPeer = (peerId, onMessage, onPeerConnected) => {
  if (connections[peerId]) {
    console.log(`Already connected to ${peerId}`);
    return;
  }
  
  const conn = peerInstance.connect(peerId);
  setupConnection(conn, onMessage, onPeerConnected);
  
  conn.on('error', (err) => {
    console.error(`Connection error with ${peerId}:`, err);
  });
  
  return conn;
};